const body = $input.first().json.body;

// Extraer campos principales
const remoteJid = body?.data?.key?.remoteJid || '';
const fromMe = body?.data?.key?.fromMe || false;
const messageText = body?.data?.message?.conversation 
  || body?.data?.message?.extendedTextMessage?.text 
  || '';
const pushName = body?.data?.pushName || '';
const phone = remoteJid.replace('@s.whatsapp.net', '').replace('@g.us', '');

// Condiciones para ignorar
const esGrupo = remoteJid.includes('@g.us');
const esMensajePropio = fromMe === true;
const esMensajeVacio = !messageText.trim();

if (esGrupo || esMensajePropio || esMensajeVacio) {
  return [{ json: { skip: "true", pass:"false" } }];
}

return [{
  json: {
    skip: "false",
    phone,
    remoteJid,
    messageText,
    pushName,
    pass:"false"
  }
}];

